export const MovieExportRequestTransitionType = {
  cinematic_cut: 'cinematic_cut',
  dissolve: 'dissolve',
  fade: 'fade',
  dream_dissolve: 'dream_dissolve',
  flashback_blur: 'flashback_blur',
  match_cut: 'match_cut',
  whip_pan: 'whip_pan',
} as const;

export type MovieExportRequestSubtitleConfig = {
  enabled?: boolean;
  language?: string;
  style?: string;
};

export type MovieExportRequestAudioLayer = {
  musicEnabled?: boolean;
  voiceEnabled?: boolean;
  effectsEnabled?: boolean;
};

/**
 * Request to assemble and export a movie from storyboard scenes
 */
export interface MovieExportRequest {
  storyboardId: string;
  format: MovieExportFormat;
  /** Scene numbers in order to assemble */
  sceneOrder?: number[];
  transitionType?: MovieExportRequestTransitionType;
  subtitleConfig?: MovieExportRequestSubtitleConfig;
  audioLayer?: MovieExportRequestAudioLayer;
}

export type MovieExportStatus = typeof MovieExportStatus[keyof typeof MovieExportStatus];


export const MovieExportStatus = {
  processing: 'processing',
  completed: 'completed',
  failed: 'failed',
} as const;

/**
 * Movie export status and result
 */
export interface MovieExport {
  exportId: string;
  storyboardId: string;
  format: MovieExportFormat;
  status: MovieExportStatus;
  exportUrl?: string;
  /**
     * @minimum 0
     * @maximum 100
     */
  exportProgress?: number;
  exportError?: string;
  fileSize?: number;
  duration?: number;
  createdAt?: string;
}

/**
 * Per-scene input for batch image generation with continuity context
 */
export interface BatchImageSceneInput {
  sceneNumber: number;
  sceneImagePrompt: string;
  colorPalette?: string;
  cinematicMood?: string;
  renderStyle?: string;
  visualEngine?: string;
  characterVisualContinuity?: string;
  /** Clothing state carried from previous scene for continuity */
  previousClothingState?: string[];
  /** Lighting state carried from previous scene */
  previousLightingState?: string;
  /** Weather state carried from previous scene */
  previousWeatherState?: string;
  /** Environment state carried from previous scene */
  previousEnvironmentState?: string;
  /** Emotional states carried from previous scene */
  previousEmotionalCarryOver?: string[];
  /** Character pose context from previous scene for pose continuity */
  previousPoseContext?: string;
}

/**
 * Request to batch generate images for all storyboard scenes sequentially
 */
export interface BatchImageGenerationRequest {
  storyboardId?: string;
  scenes: BatchImageSceneInput[];
  provider?: ImageProvider;
  characterProfiles?: CharacterProfile[];
}

/**
 * Current queue status
 */
export type BatchImageGenerationStatusBatchGenerationStatus = typeof BatchImageGenerationStatusBatchGenerationStatus[keyof typeof BatchImageGenerationStatusBatchGenerationStatus];


export const BatchImageGenerationStatusBatchGenerationStatus = {
  idle: 'idle',
  running: 'running',
  completed: 'completed',
  cancelled: 'cancelled',
  failed: 'failed',
} as const;

/**
 * Per-scene results keyed by sceneNumber
 */
export type BatchImageGenerationStatusSceneResults = {[key: string]: {
  imageStatus?: string;
  imageUrl?: string;
  imageProvider?: string;
  generationTime?: number;
  generationError?: string;
  providerChain?: string[];
}};

/**
 * Real-time status of batch image generation
 */
export interface BatchImageGenerationStatus {
  /** Current queue status */
  batchGenerationStatus: BatchImageGenerationStatusBatchGenerationStatus;
  /** Scene numbers that successfully generated */
  completedScenes: number[];
  /** Scene numbers that failed */
  failedScenes: number[];
  /** Scene numbers waiting in queue */
  queuedScenes: number[];
  /** Scene currently being generated */
  activeScene?: number;
  /**
     * Overall queue progress percentage
     * @minimum 0
     * @maximum 100
     */
  queueProgress: number;
  /** Estimated remaining time in seconds */
  estimatedTimeRemaining?: number;
  /** Total number of scenes in the batch */
  totalScenes?: number;
  /** Per-scene results keyed by sceneNumber */
  sceneResults?: BatchImageGenerationStatusSceneResults;
}

export interface ApiError {
  error: string;
}

export type GetStoryboardAssetsParams = {
storyboardId: string;
};

export type GetBatchStatusParams = {
storyboardId: string;
};

export type GetProductionAnalyticsParams = {
storyboardId: string;
};

